size_t resnetv2_stream_context_size(void) {
    return sizeof(Resnetv2Stream);
}

void resnetv2_stream_init(Resnetv2Stream *context) {
    memset(context, 0, sizeof(*context));
    memcpy(context->tensors, tensor_template, sizeof(tensor_template));
    memcpy(context->nodes, node_template, sizeof(node_template));
    context->runtime.arena = context->arena;
    context->runtime.tensors = context->tensors;
    context->runtime.tensor_count = RESNETV2_STREAM_TENSOR_COUNT;
    context->runtime.nodes = context->nodes;
    context->runtime.node_count = RESNETV2_STREAM_NODE_COUNT;
    context->runtime.queue = context->queue;
    sr_runtime_reset(&context->runtime);
}

void resnetv2_stream_reset(Resnetv2Stream *context) {
    sr_runtime_reset(&context->runtime);
}

int resnetv2_stream_push(
    Resnetv2Stream *context,
    float input,
    float output[][4],
    uint32_t output_capacity_tokens) {
    if (output_capacity_tokens < RESNETV2_STREAM_MAX_OUTPUT_TOKENS_PER_PUSH) {
        return -2;
    }
    return sr_runtime_push(
        &context->runtime, 0, 20, &input,
        output_capacity_tokens ? &output[0][0] : NULL,
        output_capacity_tokens);
}
